from functools import wraps
import time
from collections import deque
import math

from flask import Flask, request, jsonify

class RateLimiter:
    """
    Basit bir in-memory kayan pencere (sliding window) tabanlı rate limiter.
    IP adresine göre istekleri sınırlar.
    """
    def __init__(self):
        # Her IP adresi için istek zaman damgalarını tutan bir deque (çift uçlu kuyruk)
        # {ip_adresi: deque(istek_zaman_damgası, ...)}
        self.requests = {}

    def limit(self, max_requests, period_seconds):
        """
        Belirtilen süre içinde yapılabilecek maksimum istek sayısını sınırlayan dekoratör.

        :param max_requests: Belirtilen süre içinde izin verilen maksimum istek sayısı.
        :param period_seconds: İsteklerin sayılacağı zaman penceresinin süresi (saniye cinsinden).
        """
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                # İstek yapan istemcinin IP adresini al
                # Prod ortamında 'X-Forwarded-For' başlığını da kontrol etmek faydalı olabilir
                # örn: request.headers.get('X-Forwarded-For', request.remote_addr)
                ip = request.remote_addr
                now = time.time()

                # IP adresi için bir kayıt yoksa yeni bir deque oluştur
                if ip not in self.requests:
                    self.requests[ip] = deque()

                # Zaman penceresi dışındaki eski istek zaman damgalarını temizle
                while self.requests[ip] and self.requests[ip][0] < now - period_seconds:
                    self.requests[ip].popleft()

                # İstek sayısı limiti aştı mı kontrol et
                if len(self.requests[ip]) >= max_requests:
                    # Bir sonraki isteğin ne zaman yapılabileceğini hesapla
                    # Penceredeki en eski isteğin süresi dolduğunda yeni bir istek yapılabilir
                    next_available_time = self.requests[ip][0] + period_seconds
                    retry_after = int(math.ceil(next_available_time - now))

                    # retry_after değerinin negatif olmamasını sağla (beklenmese de)
                    if retry_after < 0:
                        retry_after = 0

                    # 429 Too Many Requests yanıtı dön
                    return jsonify({"message": "Too Many Requests"}), 429, {'Retry-After': str(retry_after)}

                # Limiti aşmadıysa, mevcut isteğin zaman damgasını ekle
                self.requests[ip].append(now)
                # Orijinal fonksiyonu çalıştır
                return f(*args, **kwargs)
            return decorated_function
        return decorator

# Flask uygulamasını oluştur
app = Flask(__name__)
rate_limiter = RateLimiter() # RateLimiter sınıfından bir örnek oluştur

# Örnek kullanım: Ana sayfa rotası için rate limiting
@app.route('/')
@rate_limiter.limit(max_requests=5, period_seconds=10) # 10 saniyede 5 istek sınırı
def index():
    return jsonify({"message": "Welcome to the index! You can make 5 requests per 10 seconds."})

# Örnek kullanım: Korumalı bir rota için farklı bir rate limiting
@app.route('/protected')
@rate_limiter.limit(max_requests=2, period_seconds=5) # 5 saniyede 2 istek sınırı
def protected():
    return jsonify({"message": "This is a protected endpoint. You can make 2 requests per 5 seconds."})

# Örnek kullanım: Limitlenmemiş bir rota
@app.route('/unlimited')
def unlimited():
    return jsonify({"message": "This endpoint has no rate limit."})

if __name__ == '__main__':
    # Uygulamayı hata ayıklama modunda çalıştır
    # Tek bir işlemle çalıştığı için in-memory limitleyici bu senaryoda tutarlı çalışır.
    # Çoklu işlem/thread kullanan prod ortamlarında Redis gibi harici bir depolama çözümü gerekebilir.
    app.run(debug=True)
